const item = $input.item;
const data = item.json || {};
const binary = item.binary || {};

const getString = (value) => typeof value === 'string' ? value.trim() : '';

const normalizeAddressList = (value) => {
  if (Array.isArray(value)) {
    return value
      .map((v) => typeof v === 'string' ? v.trim() : '')
      .filter(Boolean)
      .join(',');
  }

  if (typeof value === 'string') {
    return value
      .split(',')
      .map((v) => v.trim())
      .filter(Boolean)
      .join(',');
  }

  return '';
};

const parseAttachmentProperties = (value) => {
  if (Array.isArray(value)) {
    return value
      .map((v) => typeof v === 'string' ? v.trim() : '')
      .filter(Boolean);
  }

  if (typeof value === 'string') {
    return value
      .split(',')
      .map((v) => v.trim())
      .filter(Boolean);
  }

  return [];
};

const to = normalizeAddressList(data.to);
const cc = normalizeAddressList(data.cc);
const bcc = normalizeAddressList(data.bcc);
const replyTo = normalizeAddressList(data.replyTo);
const senderName = getString(data.fromName);
const subject = typeof data.subject === 'string' ? data.subject : '';
const text = typeof data.text === 'string' ? data.text : '';
const html = typeof data.html === 'string' ? data.html : '';

const hasHtml = html.trim().length > 0;
const hasText = text.trim().length > 0;
const emailType = hasHtml ? 'html' : 'text';
const message = hasHtml ? html : text;

const availableBinaryKeys = Object.keys(binary);
const explicitAttachmentKeys = parseAttachmentProperties(data.attachmentBinaryProperties);

let attachmentKeys = [];
if (explicitAttachmentKeys.length > 0) {
  const binaryKeySet = new Set(availableBinaryKeys);
  attachmentKeys = explicitAttachmentKeys.filter((key) => binaryKeySet.has(key));
} else {
  attachmentKeys = availableBinaryKeys;
}

const options = {
  appendAttribution: false
};

if (cc) {
  options.ccList = cc;
}

if (bcc) {
  options.bccList = bcc;
}

if (replyTo) {
  options.replyTo = replyTo;
}

if (senderName) {
  options.senderName = senderName;
}

if (attachmentKeys.length > 0) {
  options.attachmentsUi = {
    attachmentsBinary: attachmentKeys.map((property) => ({ property }))
  };
}

let error = '';
if (!to) {
  error = 'Input field to is required and must contain at least one email address.';
}

return [{
  json: {
    to,
    subject,
    emailType,
    message,
    options,
    usedAttachmentBinaryProperties: attachmentKeys,
    okToSend: !error,
    error
  },
  binary
}];

const response = $json || {};
const statusCode = Number(response.statusCode || 0) || null;
const hasError = !!response.error || !!response.message;
const ok = !hasError && (statusCode === null || (statusCode >= 200 && statusCode < 300));
const resolved = $('Normalize and map input').item.json || {};

return [{
  json: {
    ok,
    statusCode,
    to: resolved.to || null,
    subject: resolved.subject || '',
    usedAttachmentBinaryProperties: resolved.usedAttachmentBinaryProperties || [],
    messageId: response.id || null,
    threadId: response.threadId || null,
    labelIds: response.labelIds || [],
    response
  }
}];

return [{
  json: {
    ok: false,
    statusCode: null,
    to: $json.to || null,
    subject: $json.subject || '',
    usedAttachmentBinaryProperties: $json.usedAttachmentBinaryProperties || [],
    messageId: null,
    threadId: null,
    labelIds: [],
    response: {
      error: $json.error || 'Invalid input'
    }
  }
}];
